// src/App.jsx
import React from 'react';
import { IntlProvider } from 'react-intl';
import ptBR from './i18n/locales/pt-BR.json';

// ✅ Imports dos componentes (com index.js, não precisa especificar o arquivo)
import VehicleInfo from './components/VehicleInfo';
import Map from './components/Map';
import RouteSelector from './components/RouteSelector';

// ✅ Import do Context
import { VehicleProvider } from './contexts/VehicleContext';

// ✅ Import do JSON (agora dentro de src/)
import gpsData from './frontend_data_gps.json';

import './App.scss';

const App = () => {
  const locale = 'pt-BR';
  const messages = ptBR;

  // Proteção contra dados não carregados
  if (!gpsData?.vehicle) {
    return <div>Carregando...</div>;
  }

  return (
    <IntlProvider locale={locale} messages={messages} defaultLocale="pt-BR">
      <VehicleProvider gpsData={gpsData}>
        <div className="app">
          {/* ... seu JSX ... */}
        </div>
      </VehicleProvider>
    </IntlProvider>
  );
};

export default App;  // ← DEFAULT EXPORT no App também
